"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { safeShake, triggerShake, getRandomComplete, getRandomEncourage } from "@/lib/learningMessages";

// ===== 数轴常量（SVG viewBox 单位）=====
const SVG_W = 440;
const SVG_H = 150;
const LINE_X0 = 20; // 0 的位置
const LINE_X1 = 420; // 1 的位置（线长 400px）
const LINE_Y = 95;
const SEG = (LINE_X1 - LINE_X0) / 10; // 每份 40px

// 5 个要标注的小数：显示文本 + 对应刻度索引（0..10）
const TARGETS = [
  { display: "0.1", tick: 1 },
  { display: "0.2", tick: 2 },
  { display: "0.5", tick: 5 },
  { display: "0.7", tick: 7 },
  { display: "0.9", tick: 9 },
];

// 刻度 x 坐标（viewBox 单位）
const tickX = (i: number) => LINE_X0 + i * SEG;
// 转百分比（用于 HTML 覆盖层响应式定位）
const xPct = (i: number) => (tickX(i) / SVG_W) * 100;
const yPct = (y: number) => (y / SVG_H) * 100;

export default function DrawPage() {
  const [labels, setLabels] = useState(
    TARGETS.map((t) => ({ ...t, placed: false }))
  );
  const [selected, setSelected] = useState<number | null>(null);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const [encourage, setEncourage] = useState<string | null>(null);
  const tickRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const encourageTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const showEncourage = () => {
    setEncourage(getRandomEncourage());
    if (encourageTimer.current) clearTimeout(encourageTimer.current);
    encourageTimer.current = setTimeout(() => setEncourage(null), 1800);
  };

  const allPlaced = labels.every((l) => l.placed);
  const placedCount = labels.filter((l) => l.placed).length;

  const handleTickClick = (i: number) => {
    if (selected === null) {
      // 还没选卡片：抖动卡片池提示先选
      safeShake("card-pool");
      showEncourage();
      return;
    }
    const label = labels[selected];
    if (label.placed) return;
    if (label.tick === i) {
      // 放对：固定到数轴上
      setLabels((prev) =>
        prev.map((l, idx) => (idx === selected ? { ...l, placed: true } : l))
      );
      setSelected(null);
    } else {
      // 放错：抖动该刻度，标签返回（仍保持选中以便重试）
      triggerShake(tickRefs.current[i]);
      showEncourage();
    }
  };

  const nextStep = getNextStep("decimal", "draw");

  return (
    <StepShell topicId="decimal" stepId="draw">
      {/* 情境说明 */}
      <div className="mb-6 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
        <p className="text-[var(--text)]">
          📏 把小数标到数轴上：<strong>0</strong> 和 <strong>1</strong> 之间分成了 10 份
        </p>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          点击下方卡片选中，再点击数轴上对应的位置放置
        </p>
      </div>

      <div className="space-y-6">
        {/* 数轴 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
          <div
            id="number-axis"
            className="relative mx-auto w-full"
            style={{ maxWidth: SVG_W }}
          >
            <svg
              viewBox={`0 0 ${SVG_W} ${SVG_H}`}
              className="w-full"
              style={{ height: "auto" }}
            >
              {/* 主轴 */}
              <line
                x1={LINE_X0}
                y1={LINE_Y}
                x2={LINE_X1}
                y2={LINE_Y}
                style={{ stroke: "var(--text-secondary)", strokeWidth: 2 }}
              />
              {/* 右侧箭头 */}
              <polygon
                points={`${LINE_X1},${LINE_Y} ${LINE_X1 - 10},${LINE_Y - 6} ${LINE_X1 - 10},${LINE_Y + 6}`}
                style={{ fill: "var(--text-secondary)" }}
              />
              {/* 刻度线 */}
              {Array.from({ length: 11 }).map((_, i) => {
                const major = i === 0 || i === 10;
                return (
                  <line
                    key={i}
                    x1={tickX(i)}
                    y1={LINE_Y - (major ? 9 : 5)}
                    x2={tickX(i)}
                    y2={LINE_Y + (major ? 9 : 5)}
                    style={{
                      stroke: major ? "var(--text-secondary)" : "var(--text-muted)",
                      strokeWidth: major ? 2 : 1,
                    }}
                  />
                );
              })}
              {/* 0 和 1 标签 */}
              <text
                x={tickX(0)}
                y={LINE_Y + 26}
                textAnchor="middle"
                style={{ fill: "var(--text)", fontSize: 14, fontWeight: 700 }}
              >
                0
              </text>
              <text
                x={tickX(10)}
                y={LINE_Y + 26}
                textAnchor="middle"
                style={{ fill: "var(--text)", fontSize: 14, fontWeight: 700 }}
              >
                1
              </text>
            </svg>

            {/* 可点击刻度区（1..9） */}
            {Array.from({ length: 9 }).map((_, k) => {
              const i = k + 1;
              return (
                <button
                  key={i}
                  ref={(el) => {
                    tickRefs.current[i] = el;
                  }}
                  onClick={() => handleTickClick(i)}
                  aria-label={`刻度 ${i}`}
                  className="group touch-target absolute flex -translate-x-1/2 -translate-y-1/2 cursor-pointer items-center justify-center rounded-full"
                  style={{
                    left: `${xPct(i)}%`,
                    top: `${yPct(LINE_Y)}%`,
                    width: 30,
                    height: 30,
                  }}
                >
                  <span
                    className="block h-3 w-3 rounded-full opacity-0 transition-opacity group-hover:opacity-70"
                    style={{ backgroundColor: "var(--signal-focus)" }}
                  />
                </button>
              );
            })}

            {/* 已放置的小数标签（显示在数轴上方） */}
            {labels.map((label, idx) =>
              label.placed ? (
                <div
                  key={idx}
                  className="absolute -translate-x-1/2 animate-float-in"
                  style={{
                    left: `${xPct(label.tick)}%`,
                    top: `${yPct(LINE_Y - 44)}%`,
                  }}
                >
                  <div className="flex flex-col items-center">
                    <span
                      className="rounded-full px-2.5 py-0.5 text-xs font-bold text-white shadow-[var(--shadow-sm)]"
                      style={{ backgroundColor: "var(--signal-success)" }}
                    >
                      {label.display}
                    </span>
                    <span
                      className="mt-0.5 w-0.5"
                      style={{ height: 16, backgroundColor: "var(--signal-success)" }}
                    />
                  </div>
                </div>
              ) : null
            )}
          </div>

          {/* 动态提示 */}
          <div className="mt-3 text-center">
            {encourage ? (
              <p
                className="text-sm font-medium animate-float-in"
                style={{ color: "var(--signal-shake)" }}
              >
                {encourage}
              </p>
            ) : (
              <p className="text-xs text-[var(--text-muted)]">
                {selected !== null
                  ? `已选中 ${labels[selected].display}，点击数轴上它的位置`
                  : "💡 把 0 和 1 之间分成 10 份，每份是 0.1"}
              </p>
            )}
          </div>
        </div>

        {/* 小数标签卡片池 */}
        <div
          id="card-pool"
          className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]"
        >
          <div className="mb-3 text-center text-xs text-[var(--text-muted)]">
            小数卡片（已放置 {placedCount} / {TARGETS.length}）
          </div>
          <div className="flex flex-wrap justify-center gap-3">
            {labels.map((label, idx) => {
              if (label.placed) {
                return (
                  <div
                    key={idx}
                    className="flex items-center gap-1 rounded-xl px-4 py-2 text-sm font-bold text-white opacity-60"
                    style={{ backgroundColor: "var(--signal-success)" }}
                  >
                    {label.display} ✓
                  </div>
                );
              }
              const isSelected = selected === idx;
              return (
                <button
                  key={idx}
                  onClick={() => setSelected(idx)}
                  className={`rounded-xl px-4 py-2 text-sm font-bold transition-all hover:scale-105 ${
                    isSelected
                      ? "text-white shadow-[var(--shadow-accent)]"
                      : "text-[var(--text)]"
                  }`}
                  style={{
                    backgroundColor: isSelected ? "var(--accent)" : "var(--bg-soft)",
                    border: `2px solid ${isSelected ? "var(--accent)" : "var(--border)"}`,
                  }}
                >
                  {label.display}
                </button>
              );
            })}
          </div>
        </div>

        {/* 完成卡片 */}
        {allPlaced && (
          <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
            <div className="mb-2 text-4xl">🎉</div>
            <p className="text-lg font-semibold text-[var(--text)]">{completeMsg}</p>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你把 0.1、0.2、0.5、0.7、0.9 都标到了数轴上！
            </p>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="mt-6 inline-flex items-center gap-2 rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        )}
      </div>
    </StepShell>
  );
}
